import numpy as np

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """
    Assigned Approach: Precomputed valid sleep sets + hysteresis streak.

    Refined Strategy:
    - Precompute all coverage-satisfying configurations.
    - Use a two-threshold system: HARD_LIMIT (0.8) and SAFE_LIMIT (0.74).
    - If current config > HARD_LIMIT: switch to all-active immediately.
    - If current config > SAFE_LIMIT: stay in current config (ride out the spike).
    - If current config < SAFE_LIMIT: look for a more aggressive config that 
      has been stable (feasible) for K steps.
    """
    N = len(traffic_loads)
    OFFLOAD_OVERHEAD = 2.0
    HARD_LIMIT = 0.8
    SAFE_LIMIT = 0.74
    K_STREAK = 3

    if not hasattr(sleep_policy, 'initialized'):
        all_configs = []
        for i in range(2**N):
            config = np.array([(i >> j) & 1 for j in range(N)], dtype=np.int32)
            coverage_ok = True
            for cell in range(N):
                if config[cell] == 0:
                    if np.sum(neighbor_matrix[cell] * config) == 0:
                        coverage_ok = False
                        break
            if coverage_ok:
                all_configs.append(config)

        sleep_policy.configs = np.array(all_configs)
        num_sleeping = np.sum(sleep_policy.configs == 0, axis=1)
        sleep_policy.sorted_indices = np.argsort(num_sleeping)[::-1]
        sleep_policy.streaks = np.zeros(len(all_configs), dtype=int)
        sleep_policy.initialized = True

    # Recover own_loads
    own_loads = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_loads[i] = traffic_loads[i]
        else:
            own_loads[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_loads[i] -= traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j

    # Evaluate all configs
    config_feasible = np.zeros(len(sleep_policy.configs), dtype=bool)
    config_safe = np.zeros(len(sleep_policy.configs), dtype=bool)

    for idx, cfg in enumerate(sleep_policy.configs):
        overload_hard = False
        overload_safe = False
        for i in range(N):
            if cfg[i] == 1:
                eff_load = own_loads[i]
                for j in range(N):
                    if neighbor_matrix[i, j] == 1 and cfg[j] == 0:
                        active_nbrs_j_in_cfg = int(np.sum(neighbor_matrix[j] * cfg))
                        if active_nbrs_j_in_cfg > 0:
                            eff_load += own_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j_in_cfg

                if eff_load > HARD_LIMIT - 1e-7:
                    overload_hard = True
                    break
                if eff_load > SAFE_LIMIT + 1e-7:
                    overload_safe = True

        if not overload_hard:
            config_feasible[idx] = True
            if not overload_safe:
                config_safe[idx] = True

    # Update streaks
    for idx in range(len(sleep_policy.configs)):
        if config_feasible[idx]:
            sleep_policy.streaks[idx] += 1
        else:
            sleep_policy.streaks[idx] = 0

    # Current index
    current_idx = -1
    for idx, cfg in enumerate(sleep_policy.configs):
        if np.array_equal(cfg, prev_active):
            current_idx = idx
            break

    if current_idx == -1:
        # Fallback: find all-active
        all_active_cfg = np.ones(N, dtype=np.int32)
        for idx, cfg in enumerate(sleep_policy.configs):
            if np.array_equal(cfg, all_active_cfg):
                current_idx = idx
                break
        if current_idx == -1: return all_active_cfg

    # DECISION
    # 1. Emergency: current is overloaded
    if not config_feasible[current_idx]:
        # Find the least aggressive feasible config (closest to all-active)
        # Actually, just go to all-active to be safe and simple.
        all_active_idx = -1
        all_active_cfg = np.ones(N, dtype=np.int32)
        for idx, cfg in enumerate(sleep_policy.configs):
            if np.array_equal(cfg, all_active_cfg):
                all_active_idx = idx
                break
        if all_active_idx != -1:
            return sleep_policy.configs[all_active_idx].astype(np.int32)
        return all_active_cfg

    # 2. Upgrade: If current is safe, look for a better one
    if config_safe[current_idx]:
        for idx in sleep_policy.sorted_indices:
            # More sleepers than current
            if np.sum(sleep_policy.configs[idx] == 0) > np.sum(sleep_policy.configs[current_idx] == 0):
                if config_feasible[idx] and sleep_policy.streaks[idx] >= K_STREAK and config_safe[idx]:
                    return sleep_policy.configs[idx].astype(np.int32)

    # 3. Otherwise, stay
    return prev_active.copy()

