import numpy as np

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """Decide which cells sleep and which stay active."""

    # Constants
    OFFLOAD_OVERHEAD = 2.0
    SLEEP_ON = 0.55
    WAKE_OFF = 0.70
    MAX_SAFE = 0.76
    HARD_LIMIT = 0.80
    WAKE_PATIENCE = 4

    # Added SOFT_LIMIT which was missing in the previous attempt
    SOFT_LIMIT = 0.74 

    N = len(traffic_loads)

    # Initialize persistent state if not present
    if not hasattr(sleep_policy, 'state'):
        # state[i] = {'active': bool, 'infeasible_streak': int}
        sleep_policy.state = {i: {'active': True, 'infeasible_streak': 0} for i in range(N)}
        # Force center cell (0) to always be active in state
        sleep_policy.state[0]['active'] = True
        sleep_policy.state[0]['infeasible_streak'] = 0

    # 1. Recover base loads (own_load)
    own_load = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_load[i] = traffic_loads[i]
        else:
            own_load[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_load[i] -= (traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)

    own_load = np.maximum(own_load, 0.0)

    # 2. Determine decisions for ring cells (1-6)
    new_active = np.ones(N, dtype=np.int32)

    for i in range(1, N):
        current_is_active = bool(prev_active[i])

        if current_is_active:
            # Try to sleep
            can_sleep = False
            if own_load[i] <= SLEEP_ON:
                neighbors_ok = True
                active_nbrs_i_count = 0
                for j in range(N):
                    if neighbor_matrix[i, j] == 1 and prev_active[j] == 1:
                        active_nbrs_i_count += 1

                if active_nbrs_i_count > 0:
                    for j in range(N):
                        if neighbor_matrix[i, j] == 1 and prev_active[j] == 1:
                            added_load = (own_load[i] * OFFLOAD_OVERHEAD) / active_nbrs_i_count
                            if traffic_loads[j] + added_load > MAX_SAFE:
                                neighbors_ok = False
                                break

                if neighbors_ok:
                    can_sleep = True

            if can_sleep:
                new_active[i] = 0
                sleep_policy.state[i]['active'] = False
                sleep_policy.state[i]['infeasible_streak'] = 0
            else:
                new_active[i] = 1
                sleep_policy.state[i]['active'] = True
                if own_load[i] > SOFT_LIMIT:
                    sleep_policy.state[i]['infeasible_streak'] += 1
                else:
                    sleep_policy.state[i]['infeasible_streak'] = 0
        else:
            # Currently sleeping.
            active_nbrs_i = int(np.sum(neighbor_matrix[i] * prev_active))
            if active_nbrs_i == 0:
                new_active[i] = 1
                sleep_policy.state[i]['active'] = True
                sleep_policy.state[i]['infeasible_streak'] = 0
            elif own_load[i] >= WAKE_OFF:
                sleep_policy.state[i]['infeasible_streak'] += 1
                if sleep_policy.state[i]['infeasible_streak'] >= WAKE_PATIENCE:
                    new_active[i] = 1
                    sleep_policy.state[i]['active'] = True
                    sleep_policy.state[i]['infeasible_streak'] = 0
                else:
                    new_active[i] = 0
                    sleep_policy.state[i]['active'] = False
            else:
                sleep_policy.state[i]['infeasible_streak'] = 0
                new_active[i] = 0
                sleep_policy.state[i]['active'] = False

    # FINAL SAFETY CHECK
    eff_load_new = np.zeros(N)
    for i in range(N):
        if new_active[i] == 1:
            eff_load_new[i] = own_load[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and new_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * new_active))
                    if active_nbrs_j > 0:
                        eff_load_new[i] += (own_load[j] * OFFLOAD_OVERHEAD / active_nbrs_j)
        else:
            eff_load_new[i] = own_load[i]

    if np.any(eff_load_new > HARD_LIMIT):
        return np.ones(N, dtype=np.int32)

    return new_active.astype(np.int32)

import numpy as np

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """Decide which cells sleep and which stay active.

    Assigned Approach:
    - Keep center cell (index 0) permanently active.
    - Ring cells (1-6) use two-threshold hysteresis with wake patience.
    - SLEEP_ON = 0.55, WAKE_OFF = 0.70, MAX_SAFE = 0.76.
    - Patience = 4 steps for waking.
    - Use function attributes for state.
    """
    N = len(traffic_loads)
    OFFLOAD_OVERHEAD = 2.0

    # Thresholds and parameters
    SLEEP_ON = 0.55
    WAKE_OFF = 0.70
    MAX_SAFE = 0.76
    WAKE_PATIENCE = 4

    # Initialize state if not present
    if not hasattr(sleep_policy, 'states'):
        # states[i] = {'active': bool, 'infeasible_streak': int}
        sleep_policy.states = {i: {'active': True, 'infeasible_streak': 0} for i in range(N)}
        # Align with prev_active for the first step
        for i in range(N):
            sleep_policy.states[i]['active'] = bool(prev_active[i])

    # 1. Recover own base loads
    own_load = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_load[i] = traffic_loads[i]
        else:
            own_load[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    # Count active neighbors of j to find share
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_load[i] -= traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j

    # 2. Determine new decisions
    new_active = np.ones(N, dtype=np.int32)
    # Center cell (0) is always active
    new_active[0] = 1

    # We decide for each ring cell independently based on the current (prev_active) state.
    for i in range(1, N):
        current_is_active = bool(prev_active[i])

        if current_is_active:
            # Currently active. Can we sleep?
            can_sleep = False
            if own_load[i] <= SLEEP_ON:
                # Check neighbors for overload and coverage
                neighbors = np.where(neighbor_matrix[i] == 1)[0]

                # Coverage check: at least one neighbor must be active
                if np.sum(neighbor_matrix[i] * prev_active) > 0:
                    safe_for_neighbors = True
                    for n in neighbors:
                        if prev_active[n] == 1:
                            # If i sleeps, n's load increases.
                            num_active_neighbors_of_i = np.sum(neighbor_matrix[i] * prev_active)
                            if num_active_neighbors_of_i > 0:
                                increase = (own_load[i] * OFFLOAD_OVERHEAD) / num_active_neighbors_of_i
                                if traffic_loads[n] + increase > MAX_SAFE:
                                    safe_for_neighbors = False
                                    break
                    if safe_for_neighbors:
                        can_sleep = True

            if can_sleep:
                new_active[i] = 0
                sleep_policy.states[i]['infeasible_streak'] = 0
            else:
                new_active[i] = 1
                sleep_policy.states[i]['infeasible_streak'] = 0
        else:
            # Currently sleeping. Should we wake?
            # Check if we MUST wake due to overload in the current configuration
            # (though if we are sleeping, we are not the ones causing the overload 
            # unless our presence is needed to offload others. But we are sleeping.)
            # Actually, if we are sleeping, our own_load is just our traffic.
            # If our traffic is high, we might need to wake.

            if own_load[i] >= WAKE_OFF:
                sleep_policy.states[i]['infeasible_streak'] += 1
                if sleep_policy.states[i]['infeasible_streak'] >= WAKE_PATIENCE:
                    new_active[i] = 1
                    sleep_policy.states[i]['infeasible_streak'] = 0
                else:
                    new_active[i] = 0
            else:
                new_active[i] = 0
                sleep_policy.states[i]['infeasible_streak'] = 0

    # Update internal state for next step
    for i in range(N):
        sleep_policy.states[i]['active'] = bool(new_active[i])

    return new_active.astype(np.int32)

import numpy as np

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """Decide which cells sleep and which stay active."""
    N = len(traffic_loads)
    OFFLOAD_OVERHEAD = 2.0

    # Constants from assigned approach
    SLEEP_ON = 0.55
    WAKE_OFF = 0.70
    MAX_SAFE = 0.76
    WAKE_PATIENCE = 4

    # Initialize persistent state
    if not hasattr(sleep_policy, 'states'):
        # states[i] = {'is_sleeping': bool, 'infeasible_streak': int}
        sleep_policy.states = {i: {'is_sleeping': False, 'infeasible_streak': 0} for i in range(N)}

    # 1. Recover own (base) loads
    own_load = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_load[i] = traffic_loads[i]
        else:
            own_load[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_load[i] -= (traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)

    own_load = np.maximum(own_load, 0.0)

    # New decisions
    current_active = np.ones(N, dtype=np.int32)

    # Cell 0 is always active. We only consider ring cells (1-6) for sleeping.
    for i in range(1, N):
        state = sleep_policy.states[i]

        if state['is_sleeping']:
            # Currently sleeping. Check if we need to wake up.

            # 1. Immediate wake due to overload in the current configuration
            overloaded_now = False
            for j in range(N):
                if prev_active[j] == 1 and neighbor_matrix[i, j] == 1 and prev_active[i] == 0:
                    if traffic_loads[j] > 0.8:
                        overloaded_now = True
                        break

            # 2. Hysteresis wake due to load
            if own_load[i] >= WAKE_OFF:
                state['infeasible_streak'] += 1
            else:
                state['infeasible_streak'] = 0

            if overloaded_now or state['infeasible_streak'] >= WAKE_PATIENCE:
                state['is_sleeping'] = False
                state['infeasible_streak'] = 0
                current_active[i] = 1
            else:
                current_active[i] = 0
        else:
            # Currently active. Check if we can sleep.
            can_sleep = False
            if own_load[i] <= SLEEP_ON:
                # Check overload for all active neighbours if i sleeps
                potential_overload = False
                active_neighbours = []
                for j in range(N):
                    if neighbor_matrix[i, j] == 1 and prev_active[j] == 1:
                        active_neighbours.append(j)

                if len(active_neighbours) > 0:
                    # Calculate how many active neighbours i has
                    active_nbrs_i_count = len(active_neighbours)
                    for j in active_neighbours:
                        added_load = (own_load[i] * OFFLOAD_OVERHEAD) / active_nbrs_i_count
                        if traffic_loads[j] + added_load > MAX_SAFE:
                            potential_overload = True
                            break

                    if not potential_overload:
                        can_sleep = True
                else:
                    # No active neighbours, cannot sleep (coverage)
                    can_sleep = False

            if can_sleep:
                state['is_sleeping'] = True
                state['infeasible_streak'] = 0
                current_active[i] = 0
            else:
                state['is_sleeping'] = False
                state['infeasible_streak'] = 0
                current_active[i] = 1

    # Update persistent state for next call
    for i in range(1, N):
        sleep_policy.states[i]['is_sleeping'] = (current_active[i] == 0)

    return current_active.astype(np.int32)

