                sleep_policy.state[i]['active'] = True
                sleep_policy.state[i]['sleep_duration'] = 0
                if own_load[i] > SOFT_LIMIT:
                    sleep_policy.state[i]['infeasible_streak'] += 1
                else:
                    sleep_policy.state[i]['infeasible_streak'] = 0
        else:
            # Currently sleeping.
            active_nbrs_i = int(np.sum(neighbor_matrix[i] * prev_active))

            # Check for coverage violation
            if active_nbrs_i == 0:
                new_active[i] = 1
                sleep_policy.state[i]['active'] = True
                sleep_policy.state[i]['infeasible_streak'] = 0
                sleep_policy.state[i]['sleep_duration'] = 0
            elif own_load[i] >= WAKE_OFF:
                # Check patience and min sleep
                sleep_policy.state[i]['infeasible_streak'] += 1
                if sleep_policy.state[i]['infeasible_streak'] >= WAKE_PATIENCE and sleep_policy.state[i]['sleep_duration'] >= MIN_SLEEP:
                    new_active[i] = 1
                    sleep_policy.state[i]['active'] = True
                    sleep_policy.state[i]['infeasible_streak'] = 0
                    sleep_policy.state[i]['sleep_duration'] = 0
                else:
                    new_active[i] = 0
                    sleep_policy.state[i]['active'] = False
                    sleep_policy.state[i]['sleep_duration'] += 1
            else:
                # Load is fine, stay asleep
                sleep_policy.state[i]['infeasible_streak'] = 0
                new_active[i] = 0
                sleep_policy.state[i]['active'] = False
                sleep_policy.state[i]['sleep_duration'] += 1

    # 4. Global Infeasibility Handling (Step down ring cells if center is overloaded)
    if sleep_policy.state['center_infeasible_streak'] >= WAKE_PATIENCE:
        new_active = np.ones(N, dtype=np.int32)
        for i in range(1, N):
            sleep_policy.state[i]['active'] = True
            sleep_policy.state[i]['infeasible_streak'] = 0
            sleep_policy.state[i]['sleep_duration'] = 0
        sleep_policy.state['center_infeasible_streak'] = 0

    # 5. FINAL SAFETY CHECK (Hard Limit)
    # If the current (prev_active) is already violating HARD_LIMIT, we must return all-active.
    # This is the most important safety mechanism.
    for i in range(N):
        if prev_active[i] == 1 and traffic_loads[i] > HARD_LIMIT:
