    WAKE_OFF = 0.65
    MAX_SAFE = 0.75
    HARD_LIMIT = 0.80
    WAKE_PATIENCE = 3  # Less patience to avoid overload
    MIN_SLEEP = 10     # Higher commitment
    SOFT_LIMIT = 0.74 

