def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """Decide which cells sleep and which stay active."""

    # Constants
    OFFLOAD_OVERHEAD = 2.0
    SLEEP_ON = 0.52  # Slightly increased from 0.50
    WAKE_OFF = 0.72  # Slightly increased from 0.70
    MAX_SAFE = 0.75  # Slightly increased from 0.74
    HARD_LIMIT = 0.80
    WAKE_PATIENCE = 4
    MIN_SLEEP = 6    # Decreased from 8 to be more responsive
    SOFT_LIMIT = 0.73 # Increased from 0.72

    N = len(traffic_loads)

    # Initialize persistent state if not present
    if not hasattr(sleep_policy, 'state'):
        # state[i] = {'active': bool, 'infeasible_streak': int, 'sleep_duration': int, 'center_infeasible_streak': int}
        sleep_policy.state = {i: {'active': True, 'infeasible_streak': 0, 'sleep_duration': 0} for i in range(N)}
        # Force center cell (0) to always be active in state
        sleep_policy.state[0]['active'] = True
        sleep_policy.state[0]['infeasible_streak'] = 0
        sleep_policy.state[0]['sleep_duration'] = 0
        # Global streak for center cell
        sleep_policy.center_infeasible_streak = 0

    # 1. Recover base loads (own_load)
    own_load = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_load[i] = traffic_loads[i]
        else:
            own_load[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_load[i] -= (traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)

    own_load = np.maximum(own_load, 0.0)

    # 2. Handle Center Cell (Cell 0) Global Infeasibility Streak
    # The center cell is always active. We check its effective load.
    # Effective load of cell 0 is traffic_loads[0] because it's always active.

    center_eff_load = traffic_loads[0]
    if center_eff_load > HARD_LIMIT:
        # Immediate step down: wake some ring cells. 
        # To "step down", we force all ring cells to wake up.
        sleep_policy.center_infeasible_streak = 0
        for i in range(1, N):
            sleep_policy.state[i]['active'] = True
            sleep_policy.state[i]['infeasible_streak'] = 0
            sleep_policy.state[i]['sleep_duration'] = 0
        return np.ones(N, dtype=np.int32)
    elif center_eff_load > SOFT_LIMIT:
        sleep_policy.center_infeasible_streak += 1
        if sleep_policy.center_infeasible_streak >= WAKE_PATIENCE:
            # Step down: wake some ring cells.
            sleep_policy.center_infeasible_streak = 0
            for i in range(1, N):
                sleep_policy.state[i]['active'] = True
                sleep_policy.state[i]['infeasible_streak'] = 0
                sleep_policy.state[i]['sleep_duration'] = 0
            return np.ones(N, dtype=np.int32)
    else:
        sleep_policy.center_infeasible_streak = 0

    # 3. Determine decisions for ring cells (1-6)
    new_active = np.ones(N, dtype=np.int32)

    for i in range(1, N):
        current_is_active = bool(prev_active[i])

        if current_is_active:
            # Try to sleep
            can_sleep = False
            if own_load[i] <= SLEEP_ON:
                neighbors_ok = True
                # Count active neighbors of i in the PREVIOUS config
                active_nbrs_i_count = int(np.sum(neighbor_matrix[i] * prev_active))

                if active_nbrs_i_count > 0:
                    for j in range(N):
                        if neighbor_matrix[i, j] == 1 and prev_active[j] == 1:
                            # If i sleeps, its load is distributed to its active neighbors j
                            added_load = (own_load[i] * OFFLOAD_OVERHEAD) / active_nbrs_i_count
                            if traffic_loads[j] + added_load > MAX_SAFE:
                                neighbors_ok = False
                                break
                else:
                    # No active neighbors to cover i if it sleeps
                    neighbors_ok = False

                if neighbors_ok:
                    can_sleep = True

            if can_sleep:
                new_active[i] = 0
                sleep_policy.state[i]['active'] = False
                sleep_policy.state[i]['infeasible_streak'] = 0
                sleep_policy.state[i]['sleep_duration'] += 1
            else:
                new_active[i] = 1
                sleep_policy.state[i]['active'] = True
                sleep_policy.state[i]['sleep_duration'] = 0
                if own_load[i] > SOFT_LIMIT:
                    sleep_policy.state[i]['infeasible_streak'] += 1
                else:
                    sleep_policy.state[i]['infeasible_streak'] = 0
        else:
            # Currently sleeping.
            # Check coverage: must have at least one active neighbor
            active_nbrs_i = int(np.sum(neighbor_matrix[i] * prev_active))

            if active_nbrs_i == 0:
                # Coverage violation! Must wake.
                new_active[i] = 1
                sleep_policy.state[i]['active'] = True
                sleep_policy.state[i]['infeasible_streak'] = 0
                sleep_policy.state[i]['sleep_duration'] = 0
            elif own_load[i] >= WAKE_OFF:
                # Potential wake-up
                sleep_policy.state[i]['infeasible_streak'] += 1
                if sleep_policy.state[i]['infeasible_streak'] >= WAKE_PATIENCE and sleep_policy.state[i]['sleep_duration'] >= MIN_SLEEP:
                    new_active[i] = 1
                    sleep_policy.state[i]['active'] = True
                    sleep_policy.state[i]['infeasible_streak'] = 0
                    sleep_policy.state[i]['sleep_duration'] = 0
                else:
                    new_active[i] = 0
                    sleep_policy.state[i]['active'] = False
                    sleep_policy.state[i]['sleep_duration'] += 1
            else:
                # Load is fine, stay asleep
                sleep_policy.state[i]['infeasible_streak'] = 0
                new_active[i] = 0
                sleep_policy.state[i]['active'] = False
                sleep_policy.state[i]['sleep_duration'] += 1

    # FINAL SAFETY CHECK (against HARD_LIMIT)
    # We must check if the NEW configuration is valid.
    # To check if 'new_active' is valid, we need to estimate the effective loads.
    # The effective load of an active cell in the NEW configuration is:
    # own_load[i] + sum_{j in neighbors, j is sleeping in new_active} (own_load[j] * OFFLOAD_OVERHEAD / active_nbrs_j_in_new)

    eff_load_new = np.zeros(N)
    # First, calculate active neighbors in the NEW configuration for all cells
    active_nbrs_new_count = np.zeros(N)
    for j in range(N):
        if new_active[j] == 1:
            active_nbrs_new_count += neighbor_matrix[j]

    for i in range(N):
        if new_active[i] == 1:
            eff_load_new[i] = own_load[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and new_active[j] == 0:
                    # j is a sleeping neighbor. Its load is distributed to its active neighbors.
                    # Note: active_nbrs_new_count[j] is the number of active neighbors of j in the NEW config.
                    if active_nbrs_new_count[j] > 0:
                        eff_load_new[i] += (own_load[j] * OFFLOAD_OVERHEAD / active_nbrs_new_count[j])
        else:
            # Sleeping cells don't have an "effective load" for the overload constraint
            pass

    if np.any(eff_load_new > HARD_LIMIT):
        # If the new config is invalid, fall back to all-active
        return np.ones(N, dtype=np.int32)

    return new_active.astype(np.int32)

