                 prev_active: np.ndarray) -> np.ndarray:
    """
    Implementation of the assigned approach:
    Trend-adaptive threshold with centre-cell offload sink and bidirectional hysteresis.
    Keep centre cell active as offload sink. For each ring cell, compute own base load.
    Apply bidirectional hysteresis with sleep threshold SLEEP_ON and wake threshold WAKE_OFF,
    but adapt these thresholds based on recent traffic trend using an EMA of own_load.
    Enforce minimum sleep duration of 6 steps and wake patience of 4 steps.
    """
    N = len(traffic_loads)
    OFFLOAD_OVERHEAD = 2.0

    # Base thresholds (will be adapted by trend)
    BASE_SLEEP_ON = 0.55
    BASE_WAKE_OFF = 0.70
    MAX_SAFE = 0.76
    HARD_LIMIT = 0.80
    WAKE_PATIENCE = 4
    MIN_SLEEP = 6
    EMA_ALPHA = 0.2

    # Initialize persistent state
    if not hasattr(sleep_policy, 'state'):
        # state[i] = {'active': bool, 'infeasible_streak': int, 'sleep_duration': int, 'ema_load': float}
        sleep_policy.state = {i: {
            'active': True, 
            'infeasible_streak': 0, 
            'sleep_duration': 0,
            'ema_load': 0.0
        } for i in range(N)}
        # Global infeasibility streak for the centre cell
        sleep_policy.center_infeasible_streak = 0

    # 1. Recover base loads (own_load)
    own_load = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_load[i] = traffic_loads[i]
        else:
            own_load[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_load[i] -= (traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)
    own_load = np.maximum(own_load, 0.0)

    # 2. Update EMA and Adapt Thresholds
    for i in range(N):
        # Update EMA
        if i == 0: # Center cell doesn't sleep, but we track its load for trend
            sleep_policy.state[i]['ema_load'] = own_load[i] if hasattr(sleep_policy, 'center_ema') else own_load[i]
            sleep_policy.center_ema = own_load[i]
        else:
            sleep_policy.state[i]['ema_load'] = (EMA_ALPHA * own_load[i] + (1 - EMA_ALPHA) * sleep_policy.state[i]['ema_load'])

    # 3. Global center cell check
    center_eff_load = traffic_loads[0]
    if center_eff_load > HARD_LIMIT:
        # Immediate step down: wake all ring cells
        sleep_policy.center_infeasible_streak = 0
        for i in range(1, N):
            sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0})
        return np.ones(N, dtype=np.int32)
    elif center_eff_load > MAX_SAFE:
        sleep_policy.center_infeasible_streak += 1
    else:
        sleep_policy.center_infeasible_streak = 0

