        sleep_policy.center_infeasible_streak = 0
        for i in range(1, N):
            sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0})
        return np.ones(N, dtype=np.int32)

    # 4. Determine decisions for ring cells (1-6)
    new_active = np.ones(N, dtype=np.int32)
    new_active[0] = 1 

    for i in range(1, N):
        # Trend adaptation
        # If load is increasing (current > EMA), raise WAKE_OFF to delay waking? 
        # Actually, if load is increasing, we want to be MORE conservative (wake earlier).
        # The prompt says: "if the trend is decreasing, lower SLEEP_ON to allow earlier sleep; 
        # if increasing, raise WAKE_OFF to delay waking."
        # Wait, "raise WAKE_OFF to delay waking" means if load is increasing, we wait longer to wake? 
        # That sounds counter-intuitive for safety, but I must follow the prompt.

        trend = own_load[i] - sleep_policy.state[i]['ema_load']
        current_sleep_on = BASE_SLEEP_ON
        current_wake_off = BASE_WAKE_OFF

        if trend < 0: # Decreasing trend
            current_sleep_on -= 0.05 # Allow earlier sleep
        elif trend > 0: # Increasing trend
            current_wake_off += 0.05 # Delay waking (as per prompt)

        is_active = bool(prev_active[i])

        if is_active:
            # Try to sleep
            can_sleep = False
            if own_load[i] <= current_sleep_on:
                # Check coverage and overload for neighbors
                active_nbrs_i = np.where(neighbor_matrix[i] == 1)[0]
                active_nbrs_i_count = sum(1 for idx in active_nbrs_i if prev_active[idx] == 1)

                if active_nbrs_i_count > 0:
                    neighbors_ok = True
                    for idx in active_nbrs_i:
                        if prev_active[idx] == 1:
                            added_load = (own_load[i] * OFFLOAD_OVERHEAD) / active_nbrs_i_count
                            if traffic_loads[idx] + added_load > MAX_SAFE:
                                neighbors_ok = False
                                break
                    if neighbors_ok:
                        can_sleep = True

            if can_sleep:
                new_active[i] = 0
                sleep_policy.state[i].update({'active': False, 'infeasible_streak': 0, 'sleep_duration': sleep_policy.state[i]['sleep_duration'] + 1})
            else:
                new_active[i] = 1
                sleep_policy.state[i].update({'active': True, 'sleep_duration': 0})
                if own_load[i] > MAX_SAFE:
                    sleep_policy.state[i]['infeasible_streak'] += 1
                else:
                    sleep_policy.state[i]['infeasible_streak'] = 0
        else:
            # Currently sleeping
            active_nbrs_i_count = int(np.sum(neighbor_matrix[i] * prev_active))

            if active_nbrs_i_count == 0:
                # Coverage violation
                new_active[i] = 1
                sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0})
            elif own_load[i] >= current_wake_off:
                # Try to wake
                sleep_policy.state[i]['infeasible_streak'] += 1
                if sleep_policy.state[i]['infeasible_streak'] >= WAKE_PATIENCE and sleep_policy.state[i]['sleep_duration'] >= MIN_SLEEP:
                    new_active[i] = 1
                    sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0})
                else:
                    new_active[i] = 0
                    sleep_policy.state[i].update({'active': False, 'sleep_duration': sleep_policy.state[i]['sleep_duration'] + 1})
            else:
                new_active[i] = 0
                sleep_policy.state[i].update({'active': False, 'infeasible_streak': 0, 'sleep_duration': sleep_policy.state[i]['sleep_duration'] + 1})

    # Final Safety Check (Overload)
    eff_load_new = np.zeros(N)
    for i in range(N):
        if new_active[i] == 1:
            eff_load_new[i] = own_load[i]
            for j in range(N):
