        idx = 0
        for i, cfg in enumerate(sleep_policy.valid_configs):
            if np.array_equal(cfg, all_active):
                idx = i
                break
        sleep_policy.current_config_idx = idx
        sleep_policy.history = []

    valid_configs = sleep_policy.valid_configs
    streaks = sleep_policy.streaks
    history = sleep_policy.history

    history.append(traffic_loads.copy())
    if len(history) > 5:
        history.pop(0)

    # 2. Forecast loads using AR(1) logic
    forecasted_loads = np.zeros(N)
