import numpy as np

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """
    Implementation of the assigned approach:
    Keep the centre cell permanently active.
    For each ring cell apply bidirectional hysteresis with sleep threshold SLEEP_ON and wake threshold WAKE_OFF,
    a wake-patience counter, and a minimum sleep duration counter.
    Track a global infeasibility streak for the centre cell's effective load.
    Require a sleep-side stability streak before allowing a cell to sleep.
    """
    N = len(traffic_loads)
    OFFLOAD_OVERHEAD = 2.0

    # Thresholds and parameters
    SLEEP_ON = 0.40
    WAKE_OFF = 0.75
    MAX_SAFE = 0.74
    HARD_LIMIT = 0.80
    SOFT_LIMIT = 0.74
    WAKE_PATIENCE = 4
    MIN_SLEEP = 5
    UPGRADE_STREAK = 0

    # Initialize persistent state
    if not hasattr(sleep_policy, 'state'):
        # state[i] = {'active': bool, 'infeasible_streak': int, 'sleep_duration': int, 'stability_streak': int}
        sleep_policy.state = {i: {
            'active': True, 
            'infeasible_streak': 0, 
            'sleep_duration': 0,
            'stability_streak': 0
        } for i in range(N)}
        # Center cell (0) is always active
        sleep_policy.state[0]['active'] = True
        sleep_policy.state[0]['infeasible_streak'] = 0
        sleep_policy.state[0]['sleep_duration'] = 0
        sleep_policy.state[0]['stability_streak'] = 0
        # Global infeasibility streak for center cell
        sleep_policy.center_infeasible_streak = 0

    # 1. Recover base loads (own_load)
    own_load = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_load[i] = traffic_loads[i]
        else:
            own_load[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_load[i] -= (traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)
    own_load = np.maximum(own_load, 0.0)

    # 2. Center cell (0) monitoring
    center_eff_load = traffic_loads[0]
    if center_eff_load > HARD_LIMIT:
        sleep_policy.center_infeasible_streak = 0
        # Emergency wake all ring cells
        for i in range(1, N):
            sleep_policy.state[i]['active'] = True
            sleep_policy.state[i]['infeasible_streak'] = 0
            sleep_policy.state[i]['sleep_duration'] = 0
            sleep_policy.state[i]['stability_streak'] = 0
        return np.ones(N, dtype=np.int32)
    elif center_eff_load > SOFT_LIMIT:
        sleep_policy.center_infeasible_streak += 1
    else:
        sleep_policy.center_infeasible_streak = 0

    if sleep_policy.center_infeasible_streak >= WAKE_PATIENCE:
        sleep_policy.center_infeasible_streak = 0
        for i in range(1, N):
            sleep_policy.state[i]['active'] = True
            sleep_policy.state[i]['infeasible_streak'] = 0
            sleep_policy.state[i]['sleep_duration'] = 0
            sleep_policy.state[i]['stability_streak'] = 0
        return np.ones(N, dtype=np.int32)

    # 3. Ring cell decisions
    new_active = np.ones(N, dtype=np.int32)
    new_active[0] = 1

    for i in range(1, N):
        s = sleep_policy.state[i]
        is_active = bool(prev_active[i])

        if is_active:
            # Try to sleep
            can_sleep = False
            if own_load[i] <= SLEEP_ON:
                # Check if neighbors can absorb load
                active_nbrs_i_indices = np.where(neighbor_matrix[i] == 1)[0]
                active_nbrs_i_count = sum(1 for idx in active_nbrs_i_indices if prev_active[idx] == 1)

                if active_nbrs_i_count > 0:
                    neighbors_ok = True
                    for idx in active_nbrs_i_indices:
                        if prev_active[idx] == 1:
                            added_load = (own_load[i] * OFFLOAD_OVERHEAD) / active_nbrs_i_count
                            if traffic_loads[idx] + added_load > MAX_SAFE:
                                neighbors_ok = False
                                break
                    if neighbors_ok:
                        # Check stability streak
                        if s['stability_streak'] >= UPGRADE_STREAK:
                            can_sleep = True
                else:
                    # Coverage: must have an active neighbor
                    pass

            if can_sleep:
                new_active[i] = 0
                s['active'] = False
                s['infeasible_streak'] = 0
                s['sleep_duration'] += 1
                s['stability_streak'] = 0
            else:
                new_active[i] = 1
                s['active'] = True
                s['sleep_duration'] = 0
                s['stability_streak'] = 0
                if own_load[i] > SOFT_LIMIT:
                    s['infeasible_streak'] += 1
                else:
                    s['infeasible_streak'] = 0
        else:
            # Currently sleeping
            active_nbrs_i = int(np.sum(neighbor_matrix[i] * prev_active))

            if active_nbrs_i == 0:
                # Coverage violation
                new_active[i] = 1
                s['active'] = True
                s['infeasible_streak'] = 0
                s['sleep_duration'] = 0
                s['stability_streak'] = 0
            elif own_load[i] >= WAKE_OFF:
                # Check patience and minimum sleep
                s['infeasible_streak'] += 1
                if s['infeasible_streak'] >= WAKE_PATIENCE and s['sleep_duration'] >= MIN_SLEEP:
                    new_active[i] = 1
                    s['active'] = True
                    s['infeasible_streak'] = 0
                    s['sleep_duration'] = 0
                    s['stability_streak'] = 0
                else:
                    new_active[i] = 0
                    s['active'] = False
                    s['sleep_duration'] += 1
            else:
                # Load is low, stay asleep
                new_active[i] = 0
                s['active'] = False
                s['infeasible_streak'] = 0
