import numpy as np

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """
    Implementation of the assigned approach:
    Keep the centre cell permanently active as an offload sink. 
    For each ring cell compute its own base load by subtracting offloaded traffic from sleeping neighbours. 
    Apply bidirectional hysteresis with sleep-side stability streak (requiring K consecutive feasible steps before sleeping) 
    and wake-side patience (requiring WAKE_PATIENCE consecutive steps above threshold to wake). 
    Enforce a minimum sleep duration of MIN_SLEEP steps before a cell can be woken. 
    Track a global infeasibility streak for the centre cell’s effective load to tolerate brief spikes: 
    if centre load > HARD_LIMIT wake all ring cells immediately; 
    if centre load > SOFT_LIMIT increment streak and after WAKE_PATIENCE steps step down to a less‑aggressive ring‑cell sleep set (wake some ring cells); 
    reset streak when centre load ≤ SOFT_LIMIT. 
    Additionally, use a short‑term AR(1) forecast of each cell's load to proactively adjust SLEEP_ON and WAKE_OFF thresholds, 
    reducing reactions to transient spikes.
    """
    N = len(traffic_loads)
    OFFLOAD_OVERHEAD = 2.0
    HARD_LIMIT = 0.80
    SOFT_LIMIT = 0.74
    WAKE_PATIENCE = 4
    UPGRADE_STREAK_THRESHOLD = 10
    MIN_SLEEP_DURATION = 20

    # Base thresholds for hysteresis
    SLEEP_ON_BASE = 0.45
    WAKE_OFF_BASE = 0.65
    MAX_SAFE = 0.75

    # Initialize persistent state
    if not hasattr(sleep_policy, 'state'):
        # state[i] = {'active': bool, 'infeasible_streak': int, 'sleep_duration': int, 'upgrade_streak': int}
        sleep_policy.state = {i: {'active': True, 'infeasible_streak': 0, 'sleep_duration': 0, 'upgrade_streak': 0} for i in range(N)}
        sleep_policy.center_infeasible_streak = 0
        sleep_policy.history = []

    history = sleep_policy.history
    history.append(traffic_loads.copy())
    if len(history) > 5:
        history.pop(0)

    # 1. Forecast loads using AR(1) logic (simple linear trend)
    forecasted_increase = np.zeros(N)
    if len(history) >= 2:
        for i in range(N):
            diff = history[-1][i] - history[-2][i]
            forecasted_increase[i] = diff

    # Adjust thresholds based on forecast (proactive)
    # If load is increasing, make it harder to sleep and easier to wake
    SLEEP_ON = SLEEP_ON_BASE - 0.1 * forecasted_increase
    WAKE_OFF = WAKE_OFF_BASE - 0.1 * forecasted_increase

    # 2. Recover base loads (own_load)
    own_load = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            own_load[i] = traffic_loads[i]
        else:
            own_load[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        own_load[i] -= (traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)
    own_load = np.maximum(own_load, 0.0)

    # 3. Global center cell check
    center_eff_load = traffic_loads[0]
    if center_eff_load > HARD_LIMIT:
        sleep_policy.center_infeasible_streak = 0
        for i in range(1, N):
            sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0, 'upgrade_streak': 0})
        return np.ones(N, dtype=np.int32)
    elif center_eff_load > SOFT_LIMIT:
        sleep_policy.center_infeasible_streak += 1
    else:
        sleep_policy.center_infeasible_streak = 0

    if sleep_policy.center_infeasible_streak >= WAKE_PATIENCE:
        sleep_policy.center_infeasible_streak = 0
        # Step down: wake all ring cells
        for i in range(1, N):
            sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0, 'upgrade_streak': 0})
        return np.ones(N, dtype=np.int32)

    # 4. Determine decisions for ring cells (1-6)
    new_active = np.ones(N, dtype=np.int32)
    new_active[0] = 1 

    for i in range(1, N):
        current_is_active = bool(prev_active[i])

        if current_is_active:
            can_sleep = False
            # Check if own load is low enough
            if own_load[i] <= SLEEP_ON[i]:
                # Check if neighbors can absorb the load
                neighbors_ok = True
                active_nbrs_i_indices = np.where(neighbor_matrix[i] == 1)[0]
                active_nbrs_i_count = sum(1 for idx in active_nbrs_i_indices if prev_active[idx] == 1)

                if active_nbrs_i_count > 0:
                    for idx in active_nbrs_i_indices:
                        if prev_active[idx] == 1:
                            added_load = (own_load[i] * OFFLOAD_OVERHEAD) / active_nbrs_i_count
                            if traffic_loads[idx] + added_load > MAX_SAFE:
                                neighbors_ok = False
                                break
                else:
                    neighbors_ok = False

                # Check stability streak
                if neighbors_ok and sleep_policy.state[i]['upgrade_streak'] >= UPGRADE_STREAK_THRESHOLD:
                    can_sleep = True

            if can_sleep:
                new_active[i] = 0
                sleep_policy.state[i].update({'active': False, 'infeasible_streak': 0, 'upgrade_streak': 0})
                sleep_policy.state[i]['sleep_duration'] += 1
            else:
                new_active[i] = 1
                sleep_policy.state[i].update({'active': True, 'sleep_duration': 0})
                # Update upgrade streak
                if own_load[i] <= SLEEP_ON[i]:
                    sleep_policy.state[i]['upgrade_streak'] += 1
                else:
                    sleep_policy.state[i]['upgrade_streak'] = 0

                # Update infeasible streak (for waking)
                if own_load[i] > SOFT_LIMIT:
                    sleep_policy.state[i]['infeasible_streak'] += 1
                else:
                    sleep_policy.state[i]['infeasible_streak'] = 0
        else:
            # Currently sleeping
            active_nbrs_i = int(np.sum(neighbor_matrix[i] * prev_active))
            # Must wake if coverage is lost or load is too high
            if active_nbrs_i == 0 or own_load[i] >= WAKE_OFF[i]:
                sleep_policy.state[i]['infeasible_streak'] += 1
                if sleep_policy.state[i]['infeasible_streak'] >= WAKE_PATIENCE and sleep_policy.state[i]['sleep_duration'] >= MIN_SLEEP_DURATION:
                    new_active[i] = 1
                    sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0, 'upgrade_streak': 0})
                else:
                    new_active[i] = 0
                    sleep_policy.state[i].update({'active': False})
                    sleep_policy.state[i]['sleep_duration'] += 1
            else:
                # Stay asleep
                new_active[i] = 0
                sleep_policy.state[i].update({'active': False, 'infeasible_streak': 0})
                sleep_policy.state[i]['sleep_duration'] += 1

    # 5. Final Safety Check (Overload)
    eff_load_new = np.zeros(N)
    for i in range(N):
        if new_active[i] == 1:
            eff_load_new[i] = own_load[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and new_active[j] == 0:
                    active_nbrs_j_new = int(np.sum(neighbor_matrix[j] * new_active))
                    if active_nbrs_j_new > 0:
                        eff_load_new[i] += (own_load[j] * OFFLOAD_OVERHEAD / active_nbrs_j_new)
        else:
            eff_load_new[i] = own_load[i]

    if np.any(eff_load_new > HARD_LIMIT + 1e-7):
        return np.ones(N, dtype=np.int32)

    return new_active.astype(np.int32)

