        for i in range(1, N):
            sleep_policy.state[i].update({'active': True, 'infeasible_streak': 0, 'sleep_duration': 0, 'ema_load': 0.0, 'ema_trend': 0.0})
        return np.ones(N, dtype=np.int32)

    # 4. Determine decisions for ring cells (1-6)
    new_active = np.ones(N, dtype=np.int32)
    new_active[0] = 1 # Center always active

    for i in range(1, N):
